// 负载卸载优先级算法：功率不足时按 L1/L2 阈值依次卸非关键负载
function shedLoad(P_now, P_L2, P_L1) {
  if (P_now >= P_L2) return 'all_loads';
  if (P_now >= P_L1) return 'shed_noncritical';  // 卸科学/照明等
  return 'life_support_only';  // 仅生命维持+通信，告警 RTG 待命
}

graph TD
    P[当前功率] --> C{功率充足?}
    C -->|是| N[全部负载]
    C -->|否| T{低于 L2?}
    T -->|是| S[卸非关键]
    T -->|否| R{低于 L1?}
    R -->|是| M[仅生命维持+通信]
    R -->|否| E[告警+RTG接管]
    S --> N
    style E fill:#b91c1c33
